class Solution {
    public int minStartingIndex(String s, String pattern) {
        int m = pattern.length();
        int[] diffCount = new int[1];
        int minIndex = Integer.MAX_VALUE;

        BiFunction<Character, Character, Boolean> isMatch = (a, b) -> a.equals(b);
        BiConsumer<Integer, Integer> updateDiffCount = (i, j) -> {
            if (!isMatch.apply(s.charAt(i), pattern.charAt(j))) {
                diffCount[0]++;
            }
        };

        for (int i = 0; i < m; i++) {
            updateDiffCount.accept(i, i);
        }
        if (diffCount[0] <= 1) {
            minIndex = 0;
        }

        for (int i = m; i < s.length(); i++) {
            updateDiffCount.accept(i, i - (m - 1));
            updateDiffCount.accept(i - m, i - m);
            if (diffCount[0] <= 1) {
                minIndex = Math.min(minIndex, i - m + 1);
            }
        }
        return minIndex == Integer.MAX_VALUE ? -1 : minIndex;
    }
}
